<template>
  <div class="Message">
    <Nav></Nav>
    <div class="message">
<!--      留言页面-->
      <el-button type="primary" @click="openHandleClose">点击发表评论</el-button>
<!--      发表评论-->
      <el-drawer
          size="35%"
          title="欢迎评论!"
          :before-close="cancelForm"
          :visible.sync="dialog"
          direction="ltr"
          custom-class="demo-drawer"
          ref="drawer"
      >
        <div class="demo-drawer__content">
          <el-form :model="form">
            <el-form-item label="评论内容" :label-width="formLabelWidth">
              <el-input
                  type="textarea"
                  :rows="2"
                  placeholder="请输入内容"
                  v-model="form.content">
              </el-input>
            </el-form-item>
          </el-form>
          <div class="demo-drawer__footer">
            <el-button @click="cancelForm">取 消</el-button>
            <el-button
                type="primary"
                @click="handleClose(form)"
                :disabled="loading"
                :loading="loading">{{ loading ? '提交中 ...' : '确 定' }}</el-button>
          </div>
        </div>
      </el-drawer>
<!--      显示评论-->
      <div class="speak"v-if="message.length" >
        <ul>
          <li v-for="(item,index) in message" :key="item._id">
            <div class="contentText">
              <div class="block">
                <el-avatar size="large" :src="item.user.photo"></el-avatar>
              </div>
              <div class="p-info">
                <div class="p-username">{{item.user.user}}</div>
                <el-tag size="mini" v-show="item.user.admin">博主</el-tag>
                <div class="p-content">{{item.content}}</div>
                <div class="p-time">
                  <span>{{
                    new Date(item.date).getFullYear()
                    +"年"+
                    (new Date(item.date).getMonth()+1)
                    +"月"+
                    new Date(item.date).getDate()
                    +"日"+" "+
                    new Date(item.date).getHours()
                    +"点 "+
                    new Date(item.date).getMinutes()
                    +"分 "+
                    new Date(item.date).getSeconds()+"秒"
                    }}</span>
                  <b @click="showReply(index)">{{item.reply.ifShowMessage?"收起":"回复"}}</b>
                </div>
              </div>
            </div>
<!--            子回复-->
            <div class="contentChild" v-if="item.children.length" v-for="i in item.children">
              <div class="block">
                <el-avatar size="large" :src="i.user.photo"></el-avatar>
              </div>
              <div class="p-info">
                <div class="p-username">{{i.user.user}}</div>
                <el-tag size="mini" v-show="i.user.admin">博主</el-tag>
                <div class="p-content">{{i.content}}</div>
                <div class="p-time">
                  <span>{{
                    new Date(i.date).getFullYear()
                    +"年"+
                    (new Date(i.date).getMonth()+1)
                    +"月"+
                    new Date(i.date).getDate()
                    +"日"+" "+
                    new Date(i.date).getHours()
                    +"点 "+
                    new Date(i.date).getMinutes()
                    +"分 "+
                    new Date(i.date).getSeconds()+"秒"
                    }}</span>
                </div>
              </div>
            </div>
<!--            -->
            <div :class="['comment-reply',{'show':item.reply.ifShowMessage}]">
              <textarea v-model="item.ChildContent" :placeholder="'回复【'+item.user.user+'】：'"></textarea>
              <el-button @click="childCommit(item)" type="primary" :disabled="ifDisabled">提交</el-button>
            </div>
          </li>
        </ul>
      </div>
      <div class="nul" v-else>哦豁 暂时一条评论也没有!!快来评论吧</div>
    </div>
    <bottomFooter></bottomFooter>
  </div>
</template>

<script>
  import Nav from "../../components/Nav";
  import bottomFooter from "../../components/bottomFooter";
  //axios
  import axiosApi from '../../api/index';
  let ifLogin = axiosApi.ifLogin,//判断是否登录
      createRegister = axiosApi.createRegister,//提交评论
      getMessage = axiosApi.getMessage,//获取评论列表
      createChild = axiosApi.createChild;//提交子评论


  export default {
    name: "Message",
    components:{
      Nav,
      bottomFooter
    },
    data(){
      return{
        form:{
          content:''
        },
        formLabelWidth: '80px',
        timer: null,
        dialog: false,
        loading: false,
        //评论列表
        message:[],
        //用户的信息
        userData:{},
        ifDisabled:false
      }
    },
    watch:{
    },
    methods:{
      //打开评论
      openHandleClose(){
        this.form.content = '';
        if (this.$store.state.userIf) {
          //登陆了
          this.dialog = true;
        }else{
          //没登录
          this.$message.error({message:"请先登录在评论",duration:1500});
        }
      },
      //提交评论
      handleClose(done) {
        if (this.loading) {
          return;
        }
        //判断是否登录
        let userData = sessionStorage.userData;
        if(!userData){
          //用户信息失效
          this.$store.commit('upUserIf',false);//没有登录
          return
        }
        try {
          userData = JSON.parse(userData)
        }catch (e) {
          //用户信息失效
          this.$store.commit('upUserIf',false);//没有登录
          return
        }
        if(!userData){
          //用户信息失效
          this.$store.commit('upUserIf',false);//没有登录
          return
        }
        //判断是否禁言
        if (userData.disabled) {
          this.$message.error({message:"你以被管理员禁言",duration:1500});
          return;
        }
        this.$store.commit('upUserIf',true);

        //是否有内容
        if (!this.form.content) {
          this.$message.error({message:"请输入内容",duration:800});
          return;
        }
        //提交评论
        let text = document.createElement("div");
        text.innerHTML = this.form.content;
        text = text.innerText;
        createRegister({
          user:data.data.userData._id,
          content:text
        }).then(d=>{
          if (d.data.code) {
            this.$message.error({message:"评论失败请稍后再试",duration:1500});
            return
          }
          this.$message({message:"评论成功",duration:1500,type: 'success',offset:30});
          window.location.reload();
        });
        this.loading = true;
        this.timer = setTimeout(() => {
          // 动画关闭需要一定的时间
          setTimeout(() => {
            this.form.content = '';
            this.loading = false;
            this.dialog = false;
          }, 400);
        }, 1000);
      },
      //关闭发表评论
      cancelForm() {
        //判断是否有内容
        if (this.form.content) {
          this.$confirm('确定要关闭吗？')
            .then(d=>{
              this.loading = false;
              this.dialog = false;
              clearTimeout(this.timer);
            })
            .catch(e=>{});
          return
        }
        this.loading = false;
        this.dialog = false;
        clearTimeout(this.timer);
      },
      //回复评论
      showReply(index){
        //是否登录状态
        if (!this.$store.state.userIf) {
          this.$message.error({message:"请先登录在评论",duration:1500});
          return;
        }
        //是
        if (index === undefined) return;
        let p = this.message[index];
        //回复的输入框先清空
        if (this.message[index].ChildContent) {
          this.message[index].ChildContent = '';
        }
        p.reply.ifShowMessage = !p.reply.ifShowMessage;
      },
      //获取评论
      getMessage(){
        //获取评论
        getMessage()
            .then(data=>{
              if (!data.data.code) {
                this.message = data.data.data.map(item=>{
                  item.reply={
                    date:"",
                    ifShowMessage:false
                  };
                  return item;
                });
              }else{
                this.$message.error({message:data.data.msg,duration:1500});
              }
            })
      },

      //提交子评论
      childCommit(item){
        this.ifDisabled = true;
        //判断是否登录
        let userData = sessionStorage.userData;
        if(!userData){
          //用户信息失效
          this.$store.commit('upUserIf',false);//没有登录
          this.$message.error({message:"请先登录在评论",duration:1500});
          this.ifDisabled = false;
          return
        }
        try {
          userData = JSON.parse(userData)
        }catch (e) {
          //用户信息失效
          this.$store.commit('upUserIf',false);//没有登录
          this.$message.error({message:"请先登录在评论",duration:1500});
          this.ifDisabled = false;
          return
        }
        if(!userData){
          //用户信息失效
          this.$store.commit('upUserIf',false);//没有登录
          this.$message.error({message:"请先登录在评论",duration:1500});
          this.ifDisabled = false;
          return
        }
        this.$store.commit('upUserIf',true);
        this.userData = userData
        this.userData.disabled = this.userData.admin = '';
        //是否有内容
        if (!item.ChildContent) {
          this.$message.error({message:"请输入内容",duration:1000});
          this.ifDisabled = false;
          return;
        }
        //提交
        createChild({
          parentId:item._id,
          user:this.userData._id,
          content:item.ChildContent,
          fUser:item.user._id
        })
          .then(d=>{
            //出错
            if (d.data.code) {
              this.$message.error({message:d.data.msg,duration:1000});
              this.ifDisabled = false;
              return
            }
            this.$message({message:"评论成功",duration:1500,type: 'success'});
            window.location.reload();
          })
      }
    },
    created() {
      document.documentElement.scrollTop = 0;
      this.getMessage();
    },
    mounted() {
      document.documentElement.scrollTop = 0;
    }
  }
</script>

<style scoped lang="less">
  .message{
    max-width: 1260px;
    min-width: 1064px;
    min-height:520px;
    margin: 0 auto;
    padding: 100px 10px 15px;
  }
  .demo-drawer__footer{
    margin-left: 120px;
  }
  .speak{
    box-sizing: border-box;
    max-width: 1260px;
    min-width: 1064px;
    margin-top: 20px;
    border: 2px solid #474747;
    border-radius: 8px;
    background-color: rgba(255, 255, 255, 0.74);
    ul{
      box-sizing: border-box;
      padding: 35px 0;
      li{
        box-sizing: border-box;
        margin: 10px 0 0 10px;
        padding: 20px 0;
        border-left: 5px solid #6362ff;
        border-bottom: 1px dashed #ccc;
        .contentText{
          display: flex;
          .block{
            margin-left: 10px;
          }
          .p-info{
            padding-bottom: 20px;
            .p-username{
              display: inline-block;
              color: #006beb;
            }
            .el-tag{
              margin-left: 5px;
            }
            .p-content{
              box-sizing: border-box;
              padding: 5px 0 10px 10px;
              min-height: 30px;
              font-size: 14px;
            }
            .p-time{
              font-size: 12px;
              color: #626262;
              span{
                padding: 0 20px;
              }
              b{
                color: blue;
                cursor: pointer;
              }
            }
          }
        }
        .contentChild{
          display: flex;
          box-sizing: border-box;
          margin: 0 0 0 40px;
          padding-top: 20px;
          border-left: 5px solid blue;
          border-bottom: 1px dashed #ccc;
          .block{
            margin-left: 10px;
          }
          .p-info{
            padding-bottom: 20px;
            .p-username{
              display: inline-block;
              color: #006beb;
            }
            .el-tag{
              margin-left: 5px;
            }
            .p-content{
              box-sizing: border-box;
              padding: 5px 0 10px 10px;
              min-height: 30px;
              font-size: 14px;
            }
            .p-time{
              font-size: 12px;
              color: #626262;
              span{
                padding: 0 20px;
              }
            }
          }
        }
        .comment-reply{
          overflow: hidden;
          box-sizing: border-box;
          width: 98%;
          height: 0;
          padding-left: 50px;
          padding-top: 10px;
          transition: .5s;
          &.show{
            min-height: 120px;
          }
          textarea{
            display: block;
            width: 95%;
            height: 60px;
            border-color: #aaa;
            padding: 10px;
            box-sizing: border-box;
            resize: none;
          }
          button{
            margin-top: 8px;
            display: block;
          }
        }
        &:nth-last-child(1){
          border-bottom: none;
        }
      }
    }
  }
  .el-form{
    box-sizing: border-box;
    padding-right: 15px;
  }
  .nul{
    box-sizing: border-box;
    height: 50px;
    padding:10px;
    margin: 20px 0;
    background-color: white;
    border-radius: 10px;
    line-height: 35px;
    font-size: 16px;
    font-weight: bold;
    text-align: center;
    color: #337fff;
  }
</style>